import numpy as np
from scipy.optimize import linprog

# Define low-level heuristic operators
def greedy_construction(probabilities, constraints):
    selected = [0] * len(probabilities)
    for i in range(len(probabilities)):
        if probabilities[i] > 0:
            selected[i] = 1
            break
    return selected

def local_search_swap(solution, probabilities, constraints):
    best_score = score(solution, probabilities, constraints)
    n = len(solution)
    for i in range(n):
        for j in range(i+1, n):
            solution[i], solution[j] = solution[j], solution[i]
            current_score = score(solution, probabilities, constraints)
            if current_score > best_score:
                best_score = current_score
            else:
                solution[i], solution[j] = solution[j], solution[i]
    return solution

def perturbation(solution, probabilities, constraints):
    n = len(solution)
    for _ in range(np.random.randint(1, 3)):
        i, j = np.random.choice(n, size=2, replace=False)
        solution[i], solution[j] = solution[j], solution[i]
    return solution

def crossover_repair(solution, probabilities, constraints):
    n = len(solution)
    if np.random.rand() < 0.5:
        point = np.random.randint(1, n-1)
        new_solution = solution[:point] + [not s for s in solution[point:]]
    else:
        new_solution = [not s for s in solution]
    return local_search_swap(new_solution, probabilities, constraints) if np.random.rand() < 0.5 else new_solution

# Define the score function to evaluate solutions
def score(solution, probabilities, constraints):
    # Calculate objective value based on solution and probabilities
    total_distance = sum([probabilities[i] * (2 if solution[i] == 1 else 3) for i in range(len(probabilities))])
    fuel_consumption = total_distance / 4 + len(solution) * 100
    if fuel_consumption > constraints["fuel_limit"] or sum(solution) > constraints["max_bombs"]:
        return -np.inf
    success_prob = np.prod([probabilities[i] if solution[i] == 1 else 1 - probabilities[i] for i in range(len(probabilities))])
    return success_prob

# Hyper-heuristic selection mechanism using Roulette-wheel selection with performance-based weights
class HyperHeuristic:
    def __init__(self, operators, probabilities, constraints):
        self.operators = operators
        self.probabilities = probabilities
        self.constraints = constraints

    def select_operator(self):
        scores = [score([1 if np.random.rand() < p else 0 for p in self.probabilities], self.probabilities, self.constraints) for _ in range(len(self.operators))]
        total_score = sum(scores)
        probs = [s / total_score for s in scores]
        return np.random.choice(self.operators, p=probs)

