    solution = [0] * len(probabilities)
    for _ in range(100):
        operator = hh.select_operator()
        solution = operator(solution, probabilities, constraints)

    # Print the best objective value found
    print("OBJECTIVE_VALUE:", score(solution, probabilities, constraints))

import numpy as np
from scipy.optimize import linprog

# Define the low-level heuristic operators
def greedy_construction(x1, x2):
    # Greedy construction heuristic to maximize return
    if x1 == 1 and x2 == 0:
        return x1, x2
    elif x1 == 0 and x2 == 1:
        return x1, x2
    else:
        return (1, 0) if np.random.rand() > 0.5 else (0, 1)

def local_search_swap(x1, x2):
    # Local search swap heuristic to explore different combinations
    return (1, 0) if x1 == 0 and x2 == 1 else (0, 1) if x1 == 1 and x2 == 0 else (x1, x2)

def perturbation(x1, x2):
    # Perturbation heuristic to introduce small changes in the current solution
    return (1, 0) if np.random.rand() > 0.5 else (0, 1)

# Define the hyper-heuristic selection mechanism
def roulette_wheel_selection(weights):
    return np.random.choice([0, 1], p=weights/np.sum(weights))

def reinforcement_learning(rewards):
    # Simple epsilon-greedy approach for now
    if np.random.rand() > 0.2:  # Exploration rate of 0.2
        return np.argmax(rewards)
    else:
        return np.random.choice([0, 1])

def choice_function(recency, improvement, diversity):
    # Combines recency, improvement, and diversity for selection
    weights = (recency + improvement + diversity) / np.sum(recency + improvement + diversity)
    return roulette_wheel_selection(weights)

# Define the main function to run the hyper-heuristic
def maximize_earnings():
    # Decision variables: x1 for option 1, x2 for option 2
    c = [-0.7, -2]  # Negative because we want to maximize positive return
    A = [[1, 0], [0, 1], [1, 2]]  # Constraints matrix
    b = [100000, 0, 0]  # Constraints vector

    operators = [greedy_construction, local_search_swap, perturbation]
    rewards = {0: 0, 1: 0}  # Rewards for each operator (option)

    best_solution = None
    best_value = -np.inf

    for _ in range(100):  # Run for a configurable number of iterations
        x1, x2 = operators[reinforcement_learning([rewards[0], rewards[1]])](0, 1)

        if np.isclose(x1 + 2 * x2, 100000):  # Check the constraint for total investment
            res = linprog(c, A_ub=A[:-1], b_ub=b[:-1], bounds=(0, None))
            if res.success and -res.fun > best_value:
                best_value = -res.fun
                best_solution = (x1, x2)
                rewards[int(best_solution == (1, 0))] += 1  # Reward the operator that improved the solution

    return best_value, best_solution

# Run the hyper-heuristic and print the result
best_value, _ = maximize_earnings()
print("OBJECTIVE_VALUE:", best_value)

import numpy as np
from scipy.optimize import linprog

# Define the weights of each type of good
weights = {
    'A': 0.5,
    'B': 1.0,
    'C': 0.4,
    'D': 0.6,
    'E': 0.65
}

# Define the quantities of each type of good
quantities = {
    'A': 120,
    'B': 90,
    'C': 300,
    'D': 90,
    'E': 120
}

# Define the maximum weight per container and minimum load requirement
max_weight = 60
min_load = 18

# Number of containers needed to meet the demand for D goods
demand_for_D = 12

# Objective function: minimize the number of containers used
def objective(x):
    return -np.sum(x)  # Minimize the sum of binary variables (number of containers used)

# Constraints
def constraint_max_weight(x, weights, quantities):
    load = np.dot(weights, x * list(quantities.values()))
    return max_weight * len(x) - load  # Ensure each container does not exceed max weight

def constraint_min_load(x, weights, quantities):
    load = np.dot(weights, x * list(quantities.values()))
    return load - min_load * len(x)  # Ensure each container meets minimum load requirement

def constraint_A_C(x):
    A_loaded = sum(x * [quantities['A'] for _ in range(len(x))])
    C_loaded = sum(x * [quantities['C'] for _ in range(len(x))])
    return A_loaded - C_loaded  # Ensure A and C are loaded together if A is loaded

def constraint_D_demand(x):
    D_loaded = sum(x * [quantities['D'] for _ in range(len(x))])
    return demand_for_D - D_loaded  # Ensure at least the required number of units of D are loaded per container

# Define low-level heuristic operators
def greedy_construction(x):
    remaining_capacity = max_weight * len(x) - np.dot(weights, x * list(quantities.values()))
    while remaining_capacity >= min_load:
        for good in ['A', 'B', 'C', 'D', 'E']:
            if weights[good] <= remaining_capacity and quantities[good] > 0:
                quantities[good] -= 1
                x += np.zeros(len(x)) + (good == list(quantities.keys())[list(quantities.values()).index(1)])
                remaining_capacity -= weights[good]
    return x

def local_search_swap(x):
    for i in range(len(x)):
        if x[i] == 1:
            for good in ['A', 'B', 'C', 'D', 'E']:
                if weights[good] <= (max_weight - np.dot(weights, x * list(quantities.values()))) and quantities[good] > 0:
                    x[i] = 0
                    x[i + len(x) // 2] = good == 'A' or good == 'C'
    return x

# Define hyper-heuristic selection mechanism
def roulette_wheel_selection(weights):
    return np.random.choice([i for i in range(len(weights))], p=weights / sum(weights))

def reinforcement_learning(x, rewards):
    weights = [0] * len(x)
    for i in range(len(x)):
        if x[i] == 1:
            weights[i] += rewards[i]
    return weights

# Main hyper-heuristic framework
def run_hyper_heuristic(iterations=100):
    x = np.zeros(len(quantities))
    operators = [greedy_construction, local_search_swap]  # Add more if needed
    rewards = [0] * len(operators)

    for _ in range(iterations):
        operator = operators[roulette_wheel_selection(rewards)]
        x = operator(x)

        # Evaluate the solution and update rewards based on constraints
        cons = [{'type': 'ineq', 'fun': constraint_max_weight, 'args': (weights, quantities)},
                {'type': 'ineq', 'fun': constraint_min_load, 'args': (weights, quantities)},
                {'type': 'ineq', 'fun': constraint_A_C},
                {'type': 'ineq', 'fun': constraint_D_demand}]
        res = linprog(c=-np.ones(len(x)), A_ub=cons[0]['fun'](x, weights, quantities), b_ub=cons[0]['args'][1], method='highs')
        if all(c['fun'](res.x) >= -np.finfo(float).eps for c in cons):
            rewards = reinforcement_learning(x, [1] * len(operators))

    return res.x

# Run the hyper-heuristic with a certain number of iterations
best_solution = run_hyper_heuristic()
print("OBJECTIVE_VALUE:", -objective(best_solution))

import numpy as np
from itertools import permutations

# Data
customers = {i: (np.random.randint(1, 100), np.random.randint(1, 100)) for i in range(1, 21)}
demands = {i: np.random.randint(1, 50) for i in range(1, 21)}
time_windows = {i: (np.random.randint(0, 50), np.random.randint(50, 100)) for i in range(1, 21)}
service_times = {i: 90 for i in range(1, 21)}
depot = (np.random.randint(1, 100), np.random.randint(1, 100))
num_vehicles = 5
capacity = 200

# Distance matrix calculation
distances = np.zeros((21, 21))
for i in range(21):
    for j in range(21):
        distances[i][j] = np.sqrt((customers[i+1][0] - customers[j+1][0])**2 + (customers[i+1][1] - customers[j+1][1])**2)

# Objective function: minimize total distance traveled by all vehicles
def objective_function(routes):
    return sum(distances[route[-1], route[0]] + sum(distances[route[i], route[i+1]] for i in range(len(route) - 1)) for route in routes)

# Constraint: Each customer must be visited exactly once by one vehicle
def constraint_customers(routes):
    assigned = set()
    for route in routes:
        if len(set(route)) + 1 != len(route):  # Check for duplicates and depot visit
            return False
        assigned.update(route)
    return True

# Constraint: Total demand of all customers on a single route must not exceed the truck's maximum capacity (200 units)
def constraint_capacity(routes):
    for route in routes:
        if sum(demands[i] for i in route) > capacity:
            return False
    return True

# Constraint: Service must begin within each customer's strict 'hard time window.' Early arrivals must wait, and late arrivals are not permitted.
def constraint_time_windows(routes):
    for route in routes:
        departure_times = [0]  # Start from depot
        for i in range(len(route)):
            customer = route[i]
            prev_depot_time = departure_times[-1]
            service_start = max(prev_depot_time + distances[route[i-1], route[i]] if i > 0 else prev_depot_time, time_windows[customer][0])
            service_end = min(service_start + service_times[customer], time_windows[customer][1])
            if service_start != service_end:
                return False
            departure_times.append(service_end)
    return True

# Genetic Algorithm for VRPHTW
def generate_initial_population(num_routes, num_customers):
    population = []
    for _ in range(num_routes * 10):
        routes = [[]]
        remaining_customers = set(range(1, 21))
        while remaining_customers:
            if len(remaining_customers) <= num_vehicles - len(routes):
                for c in remaining_customers:
                    routes[-1].append(c)
                break
            customer = np.random.choice(list(remaining_customers))
            routes[-1].append(customer)
            remaining_customers.remove(customer)
        population.append(routes)
    return population

def fitness(routes):
    if not constraint_customers(routes) or not constraint_capacity(routes) or not constraint_time_windows(routes):
        return float('inf')
    return objective_function(routes)

def select_parents(population, num_parents):
    parents = []
    fitnesses = [fitness(ind) for ind in population]
    for _ in range(num_parents):
        parent = np.random.choice(population, p=[-f if f != float('inf') else 0 for f in fitnesses])
        parents.append(parent)
    return parents

def crossover(parent1, parent2):
    child_routes = []
    remaining_customers = set(range(1, 21))
    while remaining_customers:
        chosen_route = np.random.choice([0, 1])
        if len(remaining_customers) <= num_vehicles - len(child_routes):
            for c in remaining_customers:
                child_routes[-1].append(c)
            break
        customer = np.random.choice([p for p in parent1[chosen_route] + parent2[chosen_route] if p in remaining_customers])
        child_routes.append([customer])
        remaining_customers.remove(customer)
    return child_routes

def mutate(individual):
    if np.random.random() < 0.1:
        route_to_mutate = np.random.randint(0, len(individual) - 1)
        customer_to_swap = np.random.choice([c for c in individual[route_to_mutate] if c != 21])
        swap_with = np.random.choice([c for c in set(range(1, 21)) - {customer_to_swap} if c not in individual[route_to_mutate]])
        individual[route_to_mutate][individual[route_to_mutate].index(customer_to_swap)] = swap_with
    return individual

def evolve(population, num_generations):
    for generation in range(num_generations):
        population = sorted(population, key=lambda x: fitness(x) if not constraint_customers(x) or not constraint_capacity(x) or not constraint_time_windows(x) else float('inf'))[:len(population)]
        new_generation = []
        while len(new_generation) < len(population):
            parent1, parent2 = select_parents(population, 2)
            child_routes = crossover(parent1, parent2)
            if np.random.random() < 0.1:
                child_routes = mutate(child_routes)
            new_generation.append(child_routes)
        population = new_generation
    return min(population, key=lambda x: fitness(x) if not constraint_customers(x) or not constraint_capacity(x) or not constraint_time_windows(x) else float('inf'))

# Initialize population
num_routes = 10
population = generate_initial_population(num_routes, len(customers))

# Evolutionary process
num_generations = 50
best_solution = evolve(population, num_generations)

print("Best Solution Routes:", best_solution)
print("Total Distance Traveled:", objective_function(best_solution))

import numpy as np
from scipy.optimize import minimize

# Define the processing times for each product on each machine
processing_times = {
    'Product 1': {'Machine 1': 2, 'Machine 2': 3, 'Machine 3': 1},
    'Product 2': {'Machine 1': 4, 'Machine 2': 2, 'Machine 3': 3},
    'Product 3': {'Machine 1': 3, 'Machine 2': 5, 'Machine 3': 2}
}

# Define low-level heuristic operators
def greedy_construction(processing_times):
    order = []
    for product in processing_times:
        machine_times = list(processing_times[product].values())
        min_time_index = np.argmin(machine_times)
        order.append((product, list(processing_times[product].keys())[min_time_index]))
    return order

def local_search_swap(order, processing_times):
    best_order = order[:]
    for i in range(len(order)):
        for j in range(i+1, len(order)):
            product1, machine1 = order[i]
            product2, machine2 = order[j]
            if machine1 != machine2:
                new_time1 = processing_times[product1][machine2]
                new_time2 = processing_times[product2][machine1]
                if new_time1 + new_time2 < processing_times[product1][machine1] + processing_times[product2][machine2]:
                    order[i], order[j] = (product2, machine2), (product1, machine1)
    return order

def perturbation(order, processing_times):
    if len(order) < 3:
        return greedy_construction(processing_times)
    idx = np.random.choice(range(len(order)), size=2, replace=False)
    product1, machine1 = order[idx[0]]
    product2, machine2 = order[idx[1]]
    new_time1 = processing_times[product1][machine2]
    new_time2 = processing_times[product2][machine1]
    if new_time1 + new_time2 < processing_times[product1][machine1] + processing_times[product2][machine2]:
        order[idx[0]], order[idx[1]] = (product2, machine2), (product1, machine1)
    return order

# Define the hyper-heuristic selection mechanism
def roulette_wheel_selection(operators):
    fitnesses = [o['fitness'] for o in operators]
    total_fitness = sum(fitnesses)
    if total_fitness == 0:
        return np.random.choice(operators)
    wheel = [f/total_fitness for f in fitnesses]
    return operators[np.argmax(np.random.multinomial(1, wheel))]

def reinforcement_learning_selection(operators):
    best_operator = max(operators, key=lambda o: o['reward'])
    return best_operator

def choice_function_selection(operators):
    operators.sort(key=lambda o: (np.random.random(), -o['fitness']))
    return operators[0]

# Define the main hyper-heuristic function
def hyper_heuristic(iterations, selection_strategy):
    operators = [
        {'operator': greedy_construction, 'fitness': 0},
        {'operator': local_search_swap, 'fitness': 0},
        {'operator': perturbation, 'fitness': 0}
    ]

    order = []
    for _ in range(iterations):
        operator = selection_strategy(operators)
        if callable(operator['operator']):
            order = operator['operator'](processing_times)
            fitness = evaluate_order(order, processing_times)
            operator['fitness'] = fitness

    best_order = max(operators, key=lambda o: evaluate_order(o['operator'](processing_times), processing_times))['operator'](processing_times)
    return evaluate_order(best_order, processing_times)

# Define a function to evaluate the order
def evaluate_order(order, processing_times):
    total_time = 0
    for product, machine in order:
        total_time += processing_times[product][machine]
    return total_time

# Run the hyper-heuristic with roulette wheel selection
best_objective = hyper_heuristic(100, roulette_wheel_selection)
print("OBJECTIVE_VALUE:", best_objective)

import numpy as np
from scipy.optimize import linprog

# Define the low-level heuristic operators
def greedy_construction(x_A, x_B):
    # Greedy construction heuristic for model A and B
    if 4 * x_A + 6 * x_B <= 150:
        return x_A + 1, x_B
    else:
        return x_A, x_B + 1

def local_search_swap(x_A, x_B):
    # Local search swap heuristic for model A and B
    if x_A > 0 and (4 * (x_A - 1) + 6 * x_B <= 150):
        return x_A - 1, x_B
    elif x_B > 0 and (4 * x_A + 6 * (x_B - 1) <= 150):
        return x_A, x_B - 1
    else:
        return x_A, x_B

def perturbation(x_A, x_B):
    # Perturbation heuristic for model A and B
    if np.random.rand() > 0.5:
        return max(0, x_A - 1), x_B
    else:
        return x_A, max(0, x_B - 1)

def repair_operator(x_A, x_B):
    # Repair operator to satisfy constraints
    if 4 * x_A + 6 * x_B > 150:
        ratio = 150 / (4 * x_A + 6 * x_B)
        return min(x_A, int(x_A * ratio)), min(x_B, int(x_B * ratio))
    else:
        return x_A, x_B

# Define the hyper-heuristic selection mechanism
def roulette_wheel_selection(weights):
    return np.random.choice(np.arange(len(weights)), p=weights)

def reinforcement_learning_selection(rewards):
    return rewards.index(max(rewards))

def choice_function_selection(recency, improvement, diversity):
    # Simple combination of recency, improvement, and diversity
    weights = np.array([0.3 * r + 0.4 * i - 0.1 * d for r, i, d in zip(recency, improvement, diversity)])
    return np.argmax(weights)

# Define the main hyper-heuristic function
def hyper_heuristic():
    # Initial population
    population = [(x_A, x_B) for x_A in range(26) for x_B in range(17)]  # Adjusted ranges based on constraints

    best_solution = None
    best_profit = -float('inf')

    for iteration in range(50):
        operators = [greedy_construction, local_search_swap, perturbation]

        weights = []
        rewards = []
        recency = []
        improvement = []
        diversity = []

        for (x_A, x_B) in population:
            # Repair the solution to satisfy constraints
            repaired_x_A, repaired_x_B = repair_operator(x_A, x_B)

            # Evaluate objective function and constraints
            obj = 300 * repaired_x_A + 450 * repaired_x_B
            constr1 = 4 * repaired_x_A + 6 * repaired_x_B <= 150
            constr2 = 3 * repaired_x_A + 2 * repaired_x_B <= 70 if repaired_x_B > 0 else True
            constr3 = repaired_x_A >= 10 and repaired_x_B >= 15
            constr4 = 4 * repaired_x_A + 6 * repaired_x_B == 150

            if obj > best_profit:
                best_profit = obj
                best_solution = (repaired_x_A, repaired_x_B)

            # Define weights for roulette-wheel selection
            weights.append(obj)

            # Reinforcement learning rewards
            rewards.append(obj - max(0, abs(150 - (4 * repaired_x_A + 6 * repaired_x_B))))

            # Choice function metrics
            recency.append(iteration - population.index((repaired_x_A, repaired_x_B)))
            improvement.append(obj)
            diversity.append(np.linalg.norm([repaired_x_A - x_A for (x_A, _) in population] + [repaired_x_B - x_B for (_, x_B) in population]))

        # Select operator based on the strategy
        op = operators[roulette_wheel_selection(weights)]
        repaired_x_A, repaired_x_B = op(*best_solution) if np.random.rand() < 0.8 else best_solution

        # Update population
        population.append((repaired_x_A, repaired_x_B))

    return best_profit, best_solution

# Run the hyper-heuristic and print the result
best_profit, _ = hyper_heuristic()
print(f"OBJECTIVE_VALUE: {best_profit}")

