            cost = np.sum(np.array(comb) * rental_fee[list(map(lambda x: contracts.index(x), comb))] * (required_area / 100))
            if cost < min_cost:
                best_solution = comb
                min_cost = cost
    return best_solution, min_cost

def local_search_swap(current_solution, required_area, rental_fee):
    n = len(required_area)
    contracts = [1, 2, 3, 4]
    current_cost = np.sum(np.array(current_solution) * rental_fee[list(map(lambda x: contracts.index(x), current_solution))] * (required_area / 100))

    for i in range(n):
        for new_contract in [c for c in contracts if c != current_solution[i]]:
            temp_solution = list(current_solution)
            temp_solution[i] = new_contract
            temp_cost = np.sum(np.array(temp_solution) * rental_fee[list(map(lambda x: contracts.index(x), temp_solution))] * (required_area / 100))
            if temp_cost < current_cost:
                return temp_solution, temp_cost
    return current_solution, current_cost

def perturbation(current_solution, required_area, rental_fee):
    n = len(required_area)
    contracts = [1, 2, 3, 4]
    perturbed_solution = list(current_solution)
    for i in range(n):
        if np.random.rand() > 0.5:
            perturbed_solution[i] = np.random.choice([c for c in contracts if c != current_solution[i]])
    return perturbed_solution, None

# Define the hyper-heuristic selection mechanism
def roulette_wheel_selection(operators, operator_performances):
    total_performance = sum(operator_performances)
    probabilities = [perf / total_performance for perf in operator_performances]
    return np.random.choice(operators, p=probabilities)

def reinforcement_learning_selection(operators, rewards):
    action_values = [reward['reward'] for reward in rewards]
    best_action = np.argmax(action_values)
    return operators[best_action]

# Define the MILP model
def create_milp_model(required_area, rental_fee):
    n = len(required_area)
    contracts = [1, 2, 3, 4]

    # Create a CPLEX model
    model = Model('warehouse_rental')

    # Decision variables
    contract_vars = {}
    for i in range(n):
        for length in contracts:
            if length == 1 and (i+length-1 < n):
                contract_vars[(i, length)] = model.addVar(name=f'contract_{length}m_{i}', lb=0, ub=1, vtype='I')

    # Objective function
    objective = model.setObjective(np.sum([rental_fee[int(var.name[-2])] * (required_area[i]/100) for i, var in contract_vars.items()]), 'min')

    # Constraints
    for i in range(n):
        model.addConstr(np.sum([contract_vars[(i, length)] for length in contracts if (i+length-1 < n)]) == 1)

    for i in range(n):
        for length in contracts:
            if (i+length-1 < n):
                model.addConstr(contract_vars[(i, length)] * length <= required_area[i]/100)

    # Solve the model
    model.solve()

    solution = {}
    for i in range(n):
        for length in contracts:
            if (i+length-1 < n):
                var = model.getVarByName(f'contract_{length}m_{i}')
                if var.x > 0.5:
                    solution[i] = length

    total_cost = np.sum([rental_fee[int(var.name[-2])] * (required_area[i]/100) for i, var in contract_vars.items() if var.x > 0.5])

    return solution, total_cost

# Define the main function to run the hyper-heuristic
def run_hyper_heuristic(required_area, rental_fee):
    operators = [greedy_construction, local_search_swap, perturbation]
    rewards = [{'reward': 0} for _ in range(len(operators))]

    # Initial solution using greedy construction
    initial_solution, initial_cost = greedy_construction(required_area, rental_fee)
    best_solution = initial_solution
    best_cost = initial_cost

    for iteration in range(10):  # Run for a configurable number of iterations
        # Select an operator based on the hyper-heuristic strategy
        selected_operator = roulette_wheel_selection(operators, [r['reward'] for r in rewards])

        # Apply the selected operator to generate a new solution
        if selected_operator == greedy_construction:
            current_solution, current_cost = greedy_construction(required_area, rental_fee)
        elif selected_operator == local_search_swap:
            current_solution, current_cost = local_search_swap(best_solution, required_area, rental_fee)
        elif selected_operator == perturbation:
            current_solution, _ = perturbation(best_solution, required_area, rental_fee)

        # Evaluate the new solution and update rewards based on performance
        if current_cost < best_cost:
            best_solution = current_solution
            best_cost = current_cost
            for i in range(len(rewards)):
                rewards[i]['reward'] += 1

    return best_solution, best_cost

# Example usage
required_area = [1500, 1000, 2000, 1200]
rental_fee = [4000, 7500, 10500, 13000]
solution, cost = run_hyper_heuristic(required_area, rental_fee)
print(f"OBJECTIVE_VALUE: {cost}")

