# Define the penalty function for constraints
def penalty(solution):
    num_math, num_or, num_cs = 0, 0, 0
    math_selected, or_selected, cs_selected = False, False, False
    for i in range(len(solution)):
        if solution[i] == 1:
            course = courses[i]
            if course in math_courses:
                num_math += 1
                math_selected = True
            elif course in or_courses:
                num_or += 1
                or_selected = True
            elif course in cs_courses:
                num_cs += 1
                cs_selected = True

    # Check constraints
    penalty = 0
    if not math_selected and len(set([prerequisites.get(c, "") for c in or_courses + cs_courses]).intersection({"Computer Programming"})) > 0:
        penalty += 1000
    if not or_selected and "Operations Research" in courses[solution.index("Operations Research")]:
        penalty += 1000
    if not cs_selected and "Computer Science" in courses[solution.index("Data Structures")]:
        penalty += 1000

    # Additional penalties for specific course combinations
    if math_selected and solution.index("Data Structures") not in cs_courses:
        penalty += 500
    if or_selected and courses[solution.index("Operations Research")] not in or_courses:
        penalty += 500
    if cs_selected and courses[solution.index("Data Structures")] not in cs_courses:
        penalty += 500

    return penalty

# Define the objective function
def objective(solution):
    return sum(solution) + penalty(solution)

# Low-level heuristic operators
def greedy_construction(n=7):
    solution = [0] * n
    selected = set()
    for i in range(2):  # Select two courses from each category
        if i < len(math_courses):
            course = math_courses[i]
            solution[i] = 1
            selected.add(course)
        elif i < len(math_courses) + len(or_courses):
            course = or_courses[i - len(math_courses)]
            if course in selected:
                solution[i] = 1
        else:
            course = cs_courses[i - len(math_courses) - len(or_courses)]
            if course in selected:
                solution[i] = 1
    return solution

def local_search(solution):
    n = len(solution)
    for _ in range(10):  # Perform a few iterations of local search
        i = randint(0, n-1)
        if solution[i] == 0:
            solution[i] = 1
        else:
            solution[i] = 0
    return solution

def perturbation(solution):
    n = len(solution)
    for _ in range(randint(1, 3)):  # Perturb the solution a few times
        i = randint(0, n-1)
        if solution[i] == 0:
            solution[i] = 1
        else:
            solution[i] = 0
    return solution

def crossover_repair(solution):
    new_solution = list(solution)
    for i in range(len(solution)):
        if randint(0, 1) == 1:
            new_solution[i] = 1 - solution[i]
    return new_solution

# Hyper-heuristic selection mechanism
def hyper_heuristic_selection(solutions, weights=None):
    if weights is None:
        weights = [1/len(solutions)] * len(solutions)
    selected_operator = choice([greedy_construction, local_search, perturbation, crossover_repair])
    return selected_operator(solutions)

# Main optimization loop
def optimize():
    num_iterations = 100
    solutions = [greedy_construction() for _ in range(3)]
    best_solution = min(solutions, key=objective)

    for _ in range(num_iterations):
        new_solution = hyper_heuristic_selection(solutions)
        if objective(new_solution) < objective(best_solution):
            best_solution = new_solution
        solutions.append(new_solution)
        solutions = sorted(solutions, key=objective)[:3]  # Keep top 3 solutions

    return best_solution

