import numpy as np
from itertools import combinations

# Define the courses and their categories
courses = ["Calculus", "Operations Research", "Data Structures", "Management Statistics", "Computer Simulation", "Computer Programming", "Forecasting"]
categories = {"Mathematics": [0], "Operations Research": [1, 3], "Computer Science": [2, 4]}
prerequisites = {2: [5], 3: [6], 4: [6]}

# Define the objective function to minimize the number of courses taken
def objective_function(x):
    return np.sum(x)

# Define the constraints satisfaction check
def constraint_satisfaction(x, y, z):
    if (np.sum([x[i] for i in [0, 3]]) < 2 or np.sum([y[i] for i in [1, 3]]) < 2 or np.sum([z[i] for i in [2, 4]]) < 2):
        return False
    if (x[0] == 1 and z[2] != 1) or (y[1] == 1 and x[0] not in [1, 3]):
        return False
    if (z[2] == 1 and y[1] != 1) or (z[4] == 1 and x[0] != 1):
        return False
    return True

# Define the population initialization function
def initialize_population(pop_size, course_count):
    return np.random.randint(2, size=(pop_size, course_count))

# Define the mutation function
def mutate(individual, mutation_rate):
    for i in range(len(individual)):
        if np.random.rand() < mutation_rate:
            individual[i] = 1 - individual[i]
    return individual

# Define the crossover function
def crossover(parent1, parent2, crossover_rate):
    if np.random.rand() < crossover_rate:
        point = np.random.randint(len(parent1))
        child1 = np.concatenate((parent1[:point], parent2[point:]))
        child2 = np.concatenate((parent2[:point], parent1[point:]))
        return child1, child2
    else:
        return parent1, parent2

# Define the genetic algorithm function
def genetic_algorithm(population_size, iterations, mutation_rate, crossover_rate):
    course_count = len(courses)
    population = initialize_population(population_size, course_count)

    for _ in range(iterations):
        fitnesses = [objective_function([ind[i] for i in range(course_count)]) for ind in population]
        selected = np.random.choice(range(population_size), size=int(population_size/2), p=[f/sum(fitnesses) for f in fitnesses])

        new_population = []
        while len(new_population) < population_size:
            parent1, parent2 = population[selected[0]], population[selected[1]]
            child1, child2 = crossover(parent1, parent2, crossover_rate)
            child1 = mutate(child1, mutation_rate)
            child2 = mutate(child2, mutation_rate)
            while not constraint_satisfaction([child1], [], []):
                child1 = mutate(child1, mutation_rate)
            while not constraint_satisfaction([], child2, []):
                child2 = mutate(child2, mutation_rate)
            new_population.append(child1)
            new_population.append(child2)

        population = np.array(new_population[:population_size])

    best_individual = max(population, key=lambda ind: objective_function([ind[i] for i in range(course_count)]))
    return [int(x) for x in best_individual], objective_function([best_individual[i] for i in range(course_count)])

# Solve the problem using GA with recommended parameters
population_size = 50
iterations = 100
mutation_rate = 0.1
crossover_rate = 0.7

solution, objective_value = genetic_algorithm(population_size, iterations, mutation_rate, crossover_rate)
print("OBJECTIVE_VALUE:", objective_value)

