import numpy as np
from itertools import permutations

# Low-Level Heuristic Operators
def greedy_construction(distance_matrix):
    n = len(distance_matrix)
    visited = [False] * n
    path = [0]  # Start from city 0
    visited[0] = True

    for _ in range(1, n):
        current_city = path[-1]
        next_city = min([(distance_matrix[current_city][j], j) for j in range(n) if not visited[j]], key=lambda x: x[0])[1]
        path.append(next_city)
        visited[next_city] = True

    return path

def local_search_swap(path, distance_matrix):
    n = len(path)
    best_path = path[:]
    for i in range(n):
        for j in range(i + 1, n):
            new_path = path[:]
            new_path[i], new_path[j] = new_path[j], new_path[i]
            if is_valid_tour(new_path, distance_matrix) and tour_distance(new_path, distance_matrix) < tour_distance(best_path, distance_matrix):
                best_path = new_path[:]
    return best_path

def perturbation(path, k=2):
    n = len(path)
    for _ in range(k):
        i, j = np.random.choice(range(n), 2, replace=False)
        path[i], path[j] = path[j], path[i]
    return path

def is_valid_tour(path, distance_matrix):
    return len(set(path)) == len(path) and path[0] == 0 and all(distance_matrix[path[i]][path[i+1]] != 0 for i in range(len(path)-1))

def tour_distance(path, distance_matrix):
    return sum(distance_matrix[path[i]][path[i+1]] for i in range(len(path)-1)) + distance_matrix[path[-1]][path[0]]

# Hyper-Heuristic Selection Mechanism
class HyperHeuristic:
    def __init__(self, operators):
        self.operators = operators

    def select_operator(self, feedback=None):
        if feedback is None:
            return np.random.choice(self.operators)
        # Simple roulette-wheel selection based on performance (lower distance better)
        else:
            total_performance = sum([1/tour_distance([0] + list(p), distance_matrix) for p in permutations(range(1, len(distance_matrix)))])
            weights = [total_performance / tour_distance([0] + list(p), distance_matrix) for p in permutations(range(1, len(distance_matrix)))]
            return np.random.choice(self.operators, p=weights)

# Main Execution
if __name__ == "__main__":
    # Distance matrix from the problem statement
