    return sum([cost[child] for child in solution])

def swap_valid(solution, i, j, children):
    temp = solution[:]
    temp[i], temp[j] = temp[j], temp[i]
    if len(temp) == 1:
        return True
    elif len(temp) == 2:
        return not (temp[0] in ["Alice", "Charlie"] and temp[1] in ["Bob", "Diana"])
